function setPalette(name, el){
  D.palette = name; save();
  applyPalette();
  // Update active swatch
  document.querySelectorAll('.palette-swatch').forEach(s => s.classList.remove('active'));
  if(el) el.classList.add('active');
  else {
    const sw = document.getElementById('ps-'+name);
    if(sw) sw.classList.add('active');
  }
}

function applyPalette(){
  const name = D.palette || 'cyan';
  const root = document.documentElement;
  // Set data-palette attribute (drives CSS var overrides)
  root.setAttribute('data-palette', name);

  // Also apply via JS for reliability
  const pal = PALETTES[name];
  if(pal){
    // Mom-persona Phase 7: a palette can declare an underlying theme so
    // light-on-cream / sage / teal automatically gets the right text
    // contrast from light mode's :root.light overrides.
    if(pal.theme === 'light' && !root.classList.contains('light')){
      root.classList.add('light');
      try { localStorage.setItem('ylcc_theme_auto_light', '1'); } catch(e){}
    } else if(pal.theme === 'dark' && root.classList.contains('light')){
      // Only auto-flip back to dark if we were the ones who flipped to light.
      try { if(localStorage.getItem('ylcc_theme_auto_light') === '1'){ root.classList.remove('light'); localStorage.removeItem('ylcc_theme_auto_light'); } } catch(e){}
    }

    if(pal.c)   root.style.setProperty('--c',   pal.c);
    if(pal.p)   root.style.setProperty('--p',   pal.p);
    if(pal.gr)  root.style.setProperty('--gr',  pal.gr);
    if(pal.g)   root.style.setProperty('--g',   pal.g);
    if(pal.bg)  root.style.setProperty('--bg',  pal.bg);
    if(pal.s1)  root.style.setProperty('--s1',  pal.s1);
    if(pal.s2)  root.style.setProperty('--s2',  pal.s2);
    if(pal.s3)  root.style.setProperty('--s3',  pal.s3);
    if(pal.s4)  root.style.setProperty('--s4',  pal.s4);
    if(pal.tx)  root.style.setProperty('--tx',  pal.tx);
    if(pal.tx2) root.style.setProperty('--tx2', pal.tx2);
    if(pal.mt)  root.style.setProperty('--mt',  pal.mt);
  } else {
    // Reset to cyan defaults
    root.style.setProperty('--c',  '#38bdf8');
    root.style.setProperty('--p',  '#a78bfa');
    root.style.setProperty('--gr', '#34d399');
    root.style.setProperty('--g',  '#fbbf24');
    root.style.removeProperty('--bg');
    root.style.removeProperty('--s1');
    root.style.removeProperty('--s2');
    root.style.removeProperty('--s3');
    root.style.removeProperty('--s4');
    root.style.removeProperty('--tx');
    root.style.removeProperty('--tx2');
    root.style.removeProperty('--mt');
    // Auto-flip back to dark if we'd silently turned on light mode for a
    // theme palette earlier.
    try { if(localStorage.getItem('ylcc_theme_auto_light') === '1'){ root.classList.remove('light'); localStorage.removeItem('ylcc_theme_auto_light'); } } catch(e){}
  }

  // Highlight correct swatch
  document.querySelectorAll('.palette-swatch').forEach(s => {
    s.classList.toggle('active', s.dataset.palette === name);
  });

  // Cache the resolved palette tokens so the inline boot script in
  // app/index.html <head> can apply them on first paint of the *next*
  // visit — eliminates the dark-mode flash returning users on cream/sage/
  // teal saw before the full app initialized. Stored under a single key
  // (most-recent palette wins across profiles, which is what the boot
  // script needs — finishInit/applyPalette runs again with per-profile
  // data to correct anything that should differ).
  try {
    const cache = {
      name: name,
      light: document.documentElement.classList.contains('light'),
    };
    if(pal){
      ['bg','s1','s2','s3','s4','c','p','gr','g','tx','tx2','mt'].forEach(k => {
        if(pal[k]) cache[k] = pal[k];
      });
    }
    localStorage.setItem('ylcc_boot_palette_v1', JSON.stringify(cache));
  } catch(e){}
}

// ── TAX ESTIMATOR ────────────────────────────────────────────────────
function calcTax(){
  const income = parseFloat(document.getElementById('taxIncome').value) || 0;
  const status = document.getElementById('taxStatus').value;
  const type   = document.getElementById('taxType').value;
  const res    = document.getElementById('taxResult');
  if(!income || income <= 0){ if(res) res.style.display='none'; return; }
  if(res) res.style.display='block';

  // 2024 Federal brackets
  const brackets = {
    single: [[11600,.10],[47150,.12],[100525,.22],[191950,.24],[243725,.32],[609350,.35],[Infinity,.37]],
    mfj:    [[23200,.10],[94300,.12],[201050,.22],[383900,.24],[487450,.32],[731200,.35],[Infinity,.37]],
    hoh:    [[16550,.10],[63100,.12],[100500,.22],[191950,.24],[243700,.32],[609350,.35],[Infinity,.37]],
  };
  const stdDed = {single:14600, mfj:29200, hoh:21900};

  // Self-employed: deduct half of SE tax first
  let seAmt = 0;
  if(type === 'self'){
    seAmt = income * 0.9235 * 0.153;
  }

  const taxableIncome = Math.max(0, income - (seAmt / 2) - stdDed[status]);
  const bracks = brackets[status];

  let fedTax = 0;
  let prev = 0;
  let bracketDesc = '';
  let topRate = 0;
  for(const [ceiling, rate] of bracks){
    if(taxableIncome <= prev) break;
    const chunk = Math.min(taxableIncome, ceiling) - prev;
    fedTax += chunk * rate;
    if(chunk > 0){ topRate = rate; bracketDesc = `Marginal bracket: ${(rate*100).toFixed(0)}%`; }
    prev = ceiling;
  }

  const total = fedTax + seAmt;
  const effectiveRate = income > 0 ? (total / income * 100) : 0;

  const fmt = n => '$' + Math.round(n).toLocaleString();

  document.getElementById('trFed').textContent   = fmt(fedTax);
  document.getElementById('trSE').textContent    = type === 'self' ? fmt(seAmt) : '—';
  document.getElementById('trRate').textContent  = effectiveRate.toFixed(1) + '%';
  document.getElementById('trTotal').textContent = fmt(total);
  document.getElementById('trBracket').textContent = bracketDesc + ' · Standard deduction applied';

  const tip = document.getElementById('trTip');
  if(type === 'self'){
    const setAside = income * 0.28;
    tip.innerHTML = `<b>Self-employed tip:</b> Set aside ${fmt(setAside)}/year (${fmt(setAside/12)}/month) to cover taxes. Pay quarterly to avoid penalties.`;
  } else {
    const monthly = total / 12;
    tip.innerHTML = `<b>W-2 tip:</b> ${fmt(monthly)}/month should be withheld. Check your last pay stub to confirm withholding is on track.`;
  }
}

// ── THEME TOGGLE ────────────────────────────────────────────────────
function toggleTheme(){
  const isLight = document.documentElement.classList.toggle('light');
  D.theme = isLight ? 'light' : 'dark';
  save();
  updateThemeBtn();
}

function updateThemeBtn(){
  const isLight = document.documentElement.classList.contains('light');
  const label = isLight ? '☀️ Light' : '🌙 Dark';
  const icon  = isLight ? '☀️' : '🌙';
  const btn  = document.getElementById('themeBtn');
  const btnM = document.getElementById('themeBtnMob');
  const btnT = document.getElementById('themeBtnTop');
  const btnTM = document.getElementById('themeBtnTopMob');
  if(btn)  btn.textContent  = label;
  if(btnM) btnM.textContent = icon;
  if(btnT) btnT.textContent = label;
  if(btnTM) btnTM.textContent = label;
}

function applyTheme(){
  const isLight = D.theme === 'light';
  document.documentElement.classList.toggle('light', isLight);
  updateThemeBtn();
  applyCardTheme();
}

// F3-X — Card Style: 'kingdom' (purple gradient banners + glow) is the
// default that matches Christian Life Guide and Worship Playlist. 'brand'
// switches every banner/modal/card-shadow to brand cyan/violet.
function applyCardTheme(){
  const theme = (D && D.cardTheme === 'brand') ? 'brand' : 'kingdom';
  const html = document.documentElement;
  if(theme === 'brand') html.setAttribute('data-card-theme', 'brand');
  else html.removeAttribute('data-card-theme');
  // Reflect on the Settings buttons.
  const k = document.getElementById('cardThemeKingdom');
  const b = document.getElementById('cardThemeBrand');
  if(k && b){
    if(theme === 'kingdom'){
      k.style.outline = '2px solid #fff'; k.style.outlineOffset = '2px';
      b.style.outline = ''; b.style.outlineOffset = '';
    } else {
      b.style.outline = '2px solid #38bdf8'; b.style.outlineOffset = '2px';
      k.style.outline = ''; k.style.outlineOffset = '';
    }
  }
}

function setCardTheme(theme, btn){
  if(theme !== 'kingdom' && theme !== 'brand') return;
  if(!D) return;
  D.cardTheme = theme;
  if(typeof save === 'function') save();
  applyCardTheme();
}
