let _pobStep = 0;
const POB_TOTAL = 7;

function initPobDots(){
  const d = document.getElementById('pobDots'); if(!d) return;
  d.innerHTML = Array.from({length:POB_TOTAL},(_,i)=>`<div class="ob-dot${i===0?' act':''}" id="pd${i}"></div>`).join('');
}
function pobNav(dir){
  _pobStep = Math.max(0, Math.min(POB_TOTAL-1, _pobStep + dir));
  const slides = document.getElementById('pobSlides'); if(!slides) return;
  const w = slides.parentElement.offsetWidth || slides.offsetWidth;
  slides.style.transform = `translateX(-${_pobStep * w}px)`;
  document.querySelectorAll('#pobDots .ob-dot').forEach((d,i)=>d.classList.toggle('act',i===_pobStep));
  const prev = document.getElementById('pobPrev');
  const next = document.getElementById('pobNext');
  if(prev){ prev.disabled = _pobStep===0; prev.style.opacity=_pobStep===0?'0.3':'1'; }
  if(next){
    next.textContent = _pobStep === POB_TOTAL-1 ? '✅ Complete' : 'Next ›';
    if(_pobStep === POB_TOTAL-1){ next.onclick = ()=>{ closeParentOnboard(); showSection('s-hero'); }; } else { next.onclick = ()=>pobNav(1); }
  }
}
function showParentOnboard(){
  // Phase 4: Option A convergence. Users who signed up via register.html or
  // register-faith.html already declared their mode — read from
  // user_metadata.signup_source (durable across devices, unlike localStorage).
  // Only auto-route on first wizard open (parentWizardDone is set after the
  // wizard fires once, so subsequent re-opens via Start Here behave normally).
  let _autoAdvance = false;
  try {
    const src = (!D.parentWizardDone
      && typeof _supaUser !== 'undefined' && _supaUser && _supaUser.user_metadata)
      ? _supaUser.user_metadata.signup_source
      : null;
    if(src === 'register-faith' || src === 'solo'){
      // Single-person tiers (faith_free or solo) — close wizard entirely, skip
      // all tutorial slides. Phase 5.1: init.js usually catches the 'solo'
      // case first and sets parentWizardDone before the wizard ever fires;
      // this branch is belt-and-suspenders for any code path that bypasses
      // init.js (e.g., manual showParentOnboard call from Settings).
      D.soloMode = true;
      D.parentWizardDone = true;
      if(typeof save === 'function') save();
      try{ localStorage.setItem(_ylccUserKey('ylcc_parentWizardDone'), '1'); }catch(e){}
      if(typeof applySoloMode === 'function') applySoloMode();
      return; // do not open the wizard
    }
    if(src === 'register'){
      // Parent explicitly chose family mode at register.html — pre-apply and
      // auto-advance past slide 0 (mode-picker).
      D.soloMode = false;
      if(typeof save === 'function') save();
      _autoAdvance = true;
    }
  } catch(e) {}

  _pobStep = 0;
  initPobDots();
  const slides = document.getElementById('pobSlides');
  if(slides) slides.style.transform='translateX(0px)';
  const prev = document.getElementById('pobPrev');
  if(prev){ prev.disabled=true; prev.style.opacity='0.35'; }
  const next = document.getElementById('pobNext');
  if(next){ next.textContent='Next ›'; next.onclick=()=>pobNav(1); }
  const modal = document.getElementById('parentOnboard');
  if(!modal){ alert('Wizard not found — please refresh the page'); return; }
  // Force show with both inline style AND class (belt AND suspenders)
  modal.style.cssText = '';
  modal.classList.add('open');
  document.body.style.overflow='hidden';
  // Mark as seen immediately so it never auto-shows again after this visit.
  // Per-user localStorage flag survives cloudLoad() overwrites on refresh.
  D.parentWizardDone = true;
  try{ localStorage.setItem(_ylccUserKey('ylcc_parentWizardDone'), '1'); }catch(e){}
  save();

  // Auto-advance past slide 0 for register.html users (they've already chosen
  // Family mode). Tick delay lets the modal lay out so pobNav can compute
  // slide width for the translate transform.
  if(_autoAdvance){
    setTimeout(function(){ if(typeof pobNav === 'function') pobNav(1); }, 60);
  }
}
function closeParentOnboard(){
  const modal = document.getElementById('parentOnboard'); if(!modal) return;
  modal.classList.remove('open');
  modal.style.cssText = '';
  modal.style.display = 'none';
  document.body.style.overflow='';
  D.parentWizardDone = true;
  try{ localStorage.setItem(_ylccUserKey('ylcc_parentWizardDone'), '1'); }catch(e){}
  save();
  const btn = document.getElementById('startHereBtn');
  if(btn) btn.classList.add('sh-hidden');
  // Hide wizard return btn if wizard closed normally (not via wizGoTo)
  if(_wizReturnType!=='parent'){ var wb=document.getElementById('wizReturnBtn'); if(wb) wb.classList.remove('visible'); }
}

