function renderInstrGuides(){
  const el = document.getElementById('instrumentGuides'); if(!el) return;
  const search = (document.getElementById('instrSearch')||{}).value||'';
  const filtered = INSTR_GUIDES.filter(g =>
    !search || g.name.toLowerCase().includes(search.toLowerCase()) ||
    g.family.toLowerCase().includes(search.toLowerCase())
  );
  if(!filtered.length){ el.innerHTML='<div style="color:var(--tx2);font-size:.85rem;text-align:center;padding:1rem;">No instruments match your search.</div>'; return; }
  el.innerHTML = filtered.map(g => `
    <div style="background:rgba(255,255,255,.04);border:1px solid rgba(255,255,255,.08);border-radius:14px;padding:1rem;cursor:pointer;transition:all .15s;" onmouseenter="this.style.transform='translateY(-2px)';this.style.borderColor='rgba(56,189,248,.3)'" onmouseleave="this.style.transform='';this.style.borderColor='rgba(255,255,255,.08)'">
      <div style="display:flex;align-items:center;gap:.5rem;margin-bottom:.4rem;">
        <span style="font-size:1.6rem;">${g.emoji}</span>
        <div>
          <div style="font-size:.88rem;font-weight:900;color:var(--tx);">${g.name}</div>
          <div style="display:flex;gap:.4rem;margin-top:.15rem;">
            <span style="font-size:.6rem;background:rgba(56,189,248,.12);color:#38bdf8;padding:.1rem .4rem;border-radius:4px;font-weight:700;">${g.family}</span>
            <span style="font-size:.6rem;background:rgba(34,197,94,.1);color:#22c55e;padding:.1rem .4rem;border-radius:4px;font-weight:700;">${g.difficulty}</span>
          </div>
        </div>
      </div>
      <div style="font-size:.78rem;color:var(--tx2);line-height:1.6;margin-bottom:.5rem;">${g.desc}</div>
      <div style="font-size:.7rem;font-weight:800;color:var(--c);margin-bottom:.25rem;">PRO TIPS</div>
      <ul style="margin:0 0 .5rem 1rem;padding:0;">
        ${g.tips.map(t=>`<li style="font-size:.73rem;color:var(--tx2);margin-bottom:.2rem;">${t}</li>`).join('')}
      </ul>
      <div style="font-size:.68rem;color:var(--tx2);"><span style="color:var(--c);font-weight:700;">Famous players:</span> ${g.famous}</div>
      <div style="font-size:.68rem;color:var(--tx2);margin-top:.2rem;"><span style="color:var(--c);font-weight:700;">Time to basics:</span> ${g.timeToBasic}</div>
    </div>
  `).join('');
}

// ── MUSIC THEORY ──────────────────────────────────────────────
const MUSIC_THEORY = [
  { title:'The Musical Alphabet & Notes', icon:'🎵',
    body:`<p>Music uses only 7 letter names: <strong>A B C D E F G</strong> — then it repeats. These are the natural notes (the white keys on a piano).</p>
<p><strong>Sharps (#) and flats (b)</strong> are the notes in between — the black keys on a piano. A sharp raises a note by a half step; a flat lowers it by a half step.</p>
<p><strong>Half step vs whole step:</strong> A half step is the smallest distance between two notes (one key to the very next key on piano). A whole step is two half steps.</p>
<p><strong>The chromatic scale</strong> contains all 12 notes: C, C#, D, D#, E, F, F#, G, G#, A, A#, B — then back to C.</p>` },

  { title:'Reading Rhythm — Note Values', icon:'🕐',
    body:`<p>Rhythm is what happens in time. Every note has a duration:</p>
<ul>
  <li><strong>Whole note</strong> = 4 beats</li>
  <li><strong>Half note</strong> = 2 beats</li>
  <li><strong>Quarter note</strong> = 1 beat (most common)</li>
  <li><strong>Eighth note</strong> = ½ beat</li>
  <li><strong>Sixteenth note</strong> = ¼ beat</li>
</ul>
<p>A <strong>dot</strong> after a note adds half its value (dotted half = 3 beats).</p>
<p><strong>Time signature:</strong> The two numbers at the start of a piece. The top number tells you how many beats per measure; the bottom tells you which note gets one beat. 4/4 means 4 quarter-note beats per measure — the most common time signature in popular music.</p>` },

  { title:'Major Scales — The Foundation', icon:'🎼',
    body:`<p>A <strong>scale</strong> is a set of notes in order. The <strong>major scale</strong> is the most fundamental — it defines what "happy" or "bright" sounds like in Western music.</p>
<p>Every major scale follows the same pattern of whole (W) and half (H) steps:<br>
<strong>W W H W W W H</strong></p>
<p>C major is the easiest: <strong>C D E F G A B C</strong> — all white keys on piano, no sharps or flats.</p>
<p>Every other major scale follows the same pattern starting on a different note. G major: G A B C D E F# G — one sharp.</p>
<p><strong>Key signature</strong> tells you which sharps or flats apply throughout an entire piece so they don't have to be written on every note.</p>` },

  { title:'Minor Scales — The Emotional Core', icon:'🌙',
    body:`<p>Minor scales sound darker, sadder, or more mysterious than major scales. Every major key has a <strong>relative minor</strong> — they share the same notes but start on a different one.</p>
<p>The <strong>natural minor scale</strong> pattern: <strong>W H W W H W W</strong></p>
<p>A natural minor: A B C D E F G A — same notes as C major, starting on A.</p>
<p>The <strong>harmonic minor</strong> raises the 7th note by a half step, creating a dramatic leading tone. A harmonic minor: A B C D E F G# A.</p>
<p>The <strong>melodic minor</strong> raises both the 6th and 7th going up, then reverts to natural minor going down — common in classical and jazz.</p>` },

  { title:'Chords — Building Harmony', icon:'🎹',
    body:`<p>A <strong>chord</strong> is three or more notes played simultaneously. Most chords are built by stacking intervals of a third.</p>
<p><strong>Major triad</strong> = Root + Major 3rd + Perfect 5th = bright, happy (C major = C E G)</p>
<p><strong>Minor triad</strong> = Root + Minor 3rd + Perfect 5th = darker, sadder (A minor = A C E)</p>
<p><strong>Diminished triad</strong> = Root + Minor 3rd + Diminished 5th = tense, unstable</p>
<p><strong>Augmented triad</strong> = Root + Major 3rd + Augmented 5th = dreamy, mysterious</p>
<p><strong>7th chords</strong> add a fourth note a third above the 5th. Dominant 7th (G7) creates strong pull toward resolution — the core of jazz harmony.</p>` },

  { title:'Chord Progressions', icon:'🔄',
    body:`<p>Chord progressions are sequences of chords. Most popular music uses only a handful of progressions repeated with variations.</p>
<p><strong>I–V–vi–IV</strong> (e.g. C–G–Am–F in C major) is possibly the most common progression in pop music. Hundreds of hit songs use it.</p>
<p><strong>I–IV–V</strong> (e.g. C–F–G) is the foundation of blues and rock.</p>
<p><strong>ii–V–I</strong> (e.g. Dm7–G7–Cmaj7) is the most important progression in jazz.</p>
<p>Roman numerals indicate which scale degree the chord is built on. Uppercase = major chord; lowercase = minor chord.</p>
<p>Understanding progressions by number (not letter) lets you transpose any song to any key instantly.</p>` },

  { title:'Intervals — The Building Blocks', icon:'📐',
    body:`<p>An <strong>interval</strong> is the distance between two notes. Every harmony, chord, and melody is built from intervals.</p>
<ul>
  <li><strong>Unison</strong> — same note</li>
  <li><strong>Minor 2nd</strong> — 1 half step (dissonant, tension)</li>
  <li><strong>Major 2nd</strong> — 2 half steps (whole step)</li>
  <li><strong>Minor 3rd</strong> — 3 half steps (minor chord quality)</li>
  <li><strong>Major 3rd</strong> — 4 half steps (major chord quality)</li>
  <li><strong>Perfect 4th</strong> — 5 half steps (stable)</li>
  <li><strong>Tritone</strong> — 6 half steps (most dissonant interval)</li>
  <li><strong>Perfect 5th</strong> — 7 half steps (most stable interval)</li>
  <li><strong>Major 6th</strong> — 9 half steps</li>
  <li><strong>Octave</strong> — 12 half steps (same note, higher/lower)</li>
</ul>
<p>Training your ear to recognize intervals is called <strong>ear training</strong> — essential for every musician.</p>` },

  { title:'Reading Music — Staff & Clef', icon:'📖',
    body:`<p>Written music uses a <strong>staff</strong> — five horizontal lines. Notes sit on lines or in spaces between them.</p>
<p><strong>Treble clef</strong> (𝄞) is used for higher-pitched instruments and the right hand of piano. Lines from bottom to top: E G B D F (Every Good Boy Does Fine). Spaces: F A C E.</p>
<p><strong>Bass clef</strong> (𝄢) is for lower-pitched instruments and the left hand of piano. Lines: G B D F A (Good Boys Do Fine Always). Spaces: A C E G.</p>
<p><strong>Ledger lines</strong> extend the staff above or below for notes outside the staff range. Middle C sits on a ledger line between treble and bass clef.</p>
<p><strong>Reading music</strong> takes months of consistent practice but unlocks every piece of music ever written.</p>` },

  { title:'Tempo & Dynamics', icon:'🔊',
    body:`<p><strong>Tempo</strong> is the speed of music, measured in BPM (beats per minute). Common Italian terms:</p>
<ul>
  <li><strong>Largo</strong> — very slow (40–60 BPM)</li>
  <li><strong>Andante</strong> — walking pace (76–108 BPM)</li>
  <li><strong>Moderato</strong> — moderate (108–120 BPM)</li>
  <li><strong>Allegro</strong> — fast and lively (120–168 BPM)</li>
  <li><strong>Presto</strong> — very fast (168–200 BPM)</li>
</ul>
<p><strong>Dynamics</strong> indicate volume:</p>
<ul>
  <li><strong>pp</strong> (pianissimo) — very soft</li>
  <li><strong>p</strong> (piano) — soft</li>
  <li><strong>mp</strong> (mezzo-piano) — medium soft</li>
  <li><strong>mf</strong> (mezzo-forte) — medium loud</li>
  <li><strong>f</strong> (forte) — loud</li>
  <li><strong>ff</strong> (fortissimo) — very loud</li>
  <li><strong>crescendo (</strong>——<strong>&lt;)</strong> — gradually get louder</li>
  <li><strong>decrescendo (&gt;</strong>——<strong>)</strong> — gradually get softer</li>
</ul>` },

  { title:'The Circle of Fifths', icon:'⭕',
    body:`<p>The <strong>Circle of Fifths</strong> is the most important diagram in Western music theory. It shows all 12 major keys arranged in a circle, each a perfect fifth apart.</p>
<p><strong>Going clockwise:</strong> C → G → D → A → E → B → F# → C# → Ab → Eb → Bb → F → C. Each step clockwise adds one sharp to the key signature.</p>
<p><strong>Going counter-clockwise</strong> adds one flat per step.</p>
<p><strong>Why it matters:</strong></p>
<ul>
  <li>Instantly tells you how many sharps or flats are in any key</li>
  <li>Keys next to each other are most harmonically related — chord progressions naturally move around the circle</li>
  <li>The ii–V–I jazz progression moves counter-clockwise on the circle</li>
  <li>Knowing it fluently is a requirement for music school auditions</li>
</ul>` },
];

function renderMusicTheory(){
  const el = document.getElementById('theoryContent'); if(!el) return;
  el.innerHTML = MUSIC_THEORY.map((t,i) => `
    <div style="background:rgba(255,255,255,.04);border:1px solid rgba(255,255,255,.07);border-radius:14px;margin-bottom:.7rem;overflow:hidden;">
      <div style="display:flex;align-items:center;gap:.5rem;padding:.8rem 1rem;cursor:pointer;background:rgba(255,255,255,.02);" onclick="this.nextElementSibling.style.display=this.nextElementSibling.style.display==='none'?'block':'none';this.querySelector('.theory-arrow').textContent=this.nextElementSibling.style.display==='none'?'▶':'▼'">
        <span style="font-size:1.3rem;">${t.icon}</span>
        <div style="font-size:.85rem;font-weight:900;color:var(--tx);flex:1;">${t.title}</div>
        <span class="theory-arrow" style="font-size:.7rem;color:var(--tx2);">▶</span>
      </div>
      <div style="display:none;padding:.8rem 1rem 1rem;font-size:.8rem;color:var(--tx2);line-height:1.75;border-top:1px solid rgba(255,255,255,.05);">${t.body}</div>
    </div>
  `).join('');
}

// ── MUSIC PRACTICE — instruments, timer, session log ──────────

function addMyInstrument(){
  const sel = document.getElementById('addInstrument');
  const goalEl = document.getElementById('practiceGoalMin');
  const name = sel ? sel.value : '';
  if(!name){ showToast('Select an instrument first'); return; }
  if(!D.myInstruments) D.myInstruments = [];
  if(D.myInstruments.find(i => i.name===name)){ showToast('Already added!'); return; }
  D.myInstruments.push({ id:Date.now(), name, goalMin:parseInt(goalEl&&goalEl.value||60)||60, totalMin:0 });
  if(sel) sel.value = '';
  if(goalEl) goalEl.value = '';
  save();
  renderMyInstruments();
  updatePracticeSelects();
  showToast('Instrument added! 🎸');
}

function removeMyInstrument(id){
  D.myInstruments = (D.myInstruments||[]).filter(i => i.id!==id);
  save(); renderMyInstruments(); updatePracticeSelects();
}

function renderMyInstruments(){
  const el = document.getElementById('myInstrumentsList'); if(!el) return;
  const list = D.myInstruments||[];
  if(!list.length){
    el.innerHTML='<div style="font-size:.75rem;color:var(--tx2);padding:.4rem 0;">No instruments yet — add one above.</div>';
    return;
  }
  el.innerHTML = list.map(inst => {
    const pct = Math.min(100, Math.round(((inst.totalMin||0)/((inst.goalMin||60)*4))*100));
    return `<div style="display:flex;align-items:center;gap:.5rem;padding:.4rem .5rem;background:rgba(255,255,255,.04);border-radius:8px;margin-bottom:.3rem;">
      <div style="flex:1;">
        <div style="font-size:.82rem;font-weight:800;color:var(--tx);">${inst.name}</div>
        <div style="font-size:.63rem;color:var(--tx2);">Goal: ${inst.goalMin||60} min/wk · Total: ${inst.totalMin||0} min</div>
        <div style="height:3px;background:rgba(255,255,255,.08);border-radius:2px;margin-top:.25rem;">
          <div style="height:100%;width:${pct}%;background:var(--c);border-radius:2px;transition:width .4s;"></div>
        </div>
      </div>
      <button onclick="removeMyInstrument(${inst.id})" style="background:none;border:none;color:var(--tx2);cursor:pointer;font-size:.85rem;padding:.1rem .3rem;">✕</button>
    </div>`;
  }).join('');
}

function updatePracticeSelects(){
  ['practiceInstrSelect','gigInstr'].forEach(sid => {
    const sel = document.getElementById(sid); if(!sel) return;
    const cur = sel.value;
    sel.innerHTML = '<option value="">— Instrument —</option>';
    (D.myInstruments||[]).forEach(inst => {
      const opt = document.createElement('option');
      opt.value = inst.name; opt.textContent = inst.name;
      sel.appendChild(opt);
    });
    if(cur) sel.value = cur;
  });
}

// Practice timer
let _practiceInterval = null, _practiceSecs = 0, _practiceTarget = 0, _practiceRunning = false;

function setPracticeTimer(mins){
  _practiceTarget = mins * 60;
  _practiceSecs = mins * 60;
  _practiceRunning = false;
  clearInterval(_practiceInterval);
  const disp = document.getElementById('practiceTimerDisp');
  if(disp) disp.textContent = _fmtPT(_practiceSecs);
  const btn = document.getElementById('practiceStartBtn');
  if(btn) btn.textContent = '▶ Start';
}

function startPractice(){
  if(_practiceRunning){
    _practiceRunning = false;
    clearInterval(_practiceInterval);
    const btn = document.getElementById('practiceStartBtn');
    if(btn) btn.textContent = '▶ Resume';
    return;
  }
  if(_practiceSecs <= 0){ showToast('Pick a timer length first (15m, 30m...)'); return; }
  _practiceRunning = true;
  const btn = document.getElementById('practiceStartBtn');
  if(btn) btn.textContent = '⏸ Pause';
  _practiceInterval = setInterval(() => {
    if(_practiceSecs <= 0){
      clearInterval(_practiceInterval); _practiceRunning = false;
      const b = document.getElementById('practiceStartBtn'); if(b) b.textContent = '▶ Start';
      showToast('Practice complete! 🎵 Great work!');
      _savePracticeSession(_practiceTarget);
      return;
    }
    _practiceSecs--;
    const disp = document.getElementById('practiceTimerDisp');
    if(disp) disp.textContent = _fmtPT(_practiceSecs);
  }, 1000);
}

function stopPractice(){
  const elapsed = _practiceTarget - _practiceSecs;
  clearInterval(_practiceInterval); _practiceRunning = false;
  _practiceSecs = _practiceTarget;
  const disp = document.getElementById('practiceTimerDisp');
  if(disp) disp.textContent = _fmtPT(_practiceSecs);
  const btn = document.getElementById('practiceStartBtn');
  if(btn) btn.textContent = '▶ Start';
  if(elapsed > 30) _savePracticeSession(elapsed);
}

function _fmtPT(secs){
  const m = Math.floor(secs/60), s = secs%60;
  return (m<10?'0':'')+m+':'+(s<10?'0':'')+s;
}

function _savePracticeSession(elapsedSecs){
  const mins = Math.round(elapsedSecs/60); if(mins<1) return;
  const instrSel = document.getElementById('practiceInstrSelect');
  const instrName = instrSel ? instrSel.value : '';
  if(!D.practiceSessions) D.practiceSessions = [];
  D.practiceSessions.push({ id:Date.now(), instrument:instrName, mins, date:new Date().toISOString().slice(0,10) });
  if(instrName && D.myInstruments){
    const inst = D.myInstruments.find(i => i.name===instrName);
    if(inst) inst.totalMin = (inst.totalMin||0) + mins;
  }
  save(); renderMyInstruments(); renderPracticeWeek();
}

function renderPracticeWeek(){
  const el = document.getElementById('practiceWeekGrid'); if(!el) return;
  const today = new Date();
  const days = Array.from({length:7}, (_,i) => {
    const d = new Date(today); d.setDate(today.getDate()-6+i);
    return d.toISOString().slice(0,10);
  });
  const sessions = D.practiceSessions||[];
  el.innerHTML = '<div style="display:flex;gap:.3rem;justify-content:space-between;">'
    + days.map(ds => {
      const dayMins = sessions.filter(s=>s.date===ds).reduce((a,s)=>a+s.mins,0);
      const h = Math.max(4, Math.min(50, dayMins));
      const label = ['S','M','T','W','T','F','S'][new Date(ds+'T12:00:00').getDay()];
      return `<div style="flex:1;text-align:center;">
        <div style="height:${h}px;background:${dayMins?'var(--c)':'rgba(255,255,255,.08)'};border-radius:3px;margin-bottom:.2rem;"></div>
        <div style="font-size:.55rem;color:var(--tx2);">${label}</div>
        ${dayMins?`<div style="font-size:.55rem;color:var(--c);">${dayMins}m</div>`:''}
      </div>`;
    }).join('')
    + '</div>';
}

function logGig(){
  const instr = (document.getElementById('gigInstr')||{}).value||'';
  const title = ((document.getElementById('gigTitle')||{}).value||'').trim();
  const date  = (document.getElementById('gigDate')||{}).value||new Date().toISOString().slice(0,10);
  const mins  = parseInt((document.getElementById('gigMins')||{}).value)||0;
  const notes = ((document.getElementById('gigNotes')||{}).value||'').trim();
  if(!title){ showToast('Enter a session title'); return; }
  if(!D.gigLog) D.gigLog=[];
  D.gigLog.unshift({ id:Date.now(), instrument:instr, title, date, mins, notes });
  ['gigTitle','gigNotes','gigMins'].forEach(id=>{ const e=document.getElementById(id); if(e) e.value=''; });
  if(instr && mins && D.myInstruments){
    const inst = D.myInstruments.find(i=>i.name===instr);
    if(inst) inst.totalMin = (inst.totalMin||0) + mins;
  }
  save(); renderGigLog(); renderMyInstruments();
  showToast('Session logged! 🎧');
}

function renderGigLog(){
  const el = document.getElementById('gigLog'); if(!el) return;
  const log = D.gigLog||[];
  if(!log.length){ el.innerHTML='<div style="font-size:.75rem;color:var(--tx2);text-align:center;padding:1rem;">No sessions logged yet.</div>'; return; }
  el.innerHTML = log.map(g => `
    <div style="padding:.5rem .6rem;border-bottom:1px solid rgba(255,255,255,.04);">
      <div style="display:flex;align-items:center;justify-content:space-between;">
        <div>
          <div style="font-size:.8rem;font-weight:800;color:var(--tx);">${g.title}${g.mins?` <span style="color:var(--c);font-weight:400;font-size:.7rem;">${g.mins}min</span>`:''}</div>
          <div style="font-size:.65rem;color:var(--tx2);">${g.instrument?g.instrument+' · ':''}${g.date}</div>
          ${g.notes?`<div style="font-size:.7rem;color:var(--tx2);margin-top:.1rem;">${g.notes}</div>`:''}
        </div>
        <button onclick="D.gigLog=D.gigLog.filter(x=>x.id!=${g.id});save();renderGigLog();" style="background:none;border:none;color:var(--tx2);cursor:pointer;font-size:.85rem;padding:.2rem .4rem;">✕</button>
      </div>
    </div>
  `).join('');
}

// Re-run on craft section open
const _origBCS = typeof buildCraftSection==='function' ? buildCraftSection : null;
window.buildCraftSection = function(){
  if(_origBCS) _origBCS();
  renderMyInstruments();
  updatePracticeSelects();
  renderPracticeWeek();
  renderGigLog();
  const gd = document.getElementById('gigDate');
  if(gd && !gd.value) gd.value = new Date().toISOString().slice(0,10);
};
window.initMusicAndSports = window.buildCraftSection;
